// ── Inputs ─────────────────────────────────────────────────────────────────
const gaps = $('Load Gap Windows').all().map(i => i.json);
const marketRows = $('Load Market Data').all().map(i => i.json);
const csRows = $('Load Competitor Sources').all();

// ── Market data from competitor_sources (C1.5 weighted) ─────────────────
const csData = csRows.length > 0 ? csRows[0].json : null;
let csMedian = csData?.market_median ? parseFloat(csData.market_median) : null;
const csWeightedAvg = csData?.weighted_avg ? parseFloat(csData.weighted_avg) : null;
const csMin = csData?.market_min ? parseFloat(csData.market_min) : null;
const csMax = csData?.market_max ? parseFloat(csData.market_max) : null;
const hasStaleData = csData?.has_stale_data === true;
const freshCount = csData?.fresh_count ? parseInt(csData.fresh_count) : 0;
const sourceCount = csData?.source_count ? parseInt(csData.source_count) : 0;
const sourceDetails = csData?.source_details || [];

// ── Market data from competitor_prices (C1 legacy) ────────────────────────
const legacyPrices = marketRows.map(r => parseFloat(r.price_per_night)).filter(p => p > 0);
const legacyMedian = legacyPrices.length > 0
  ? legacyPrices.sort((a,b)=>a-b)[Math.floor(legacyPrices.length/2)]
  : null;

// Use C1.5 sources if available (priority), fall back to C1 legacy
const market_median = csMedian || csWeightedAvg || legacyMedian;
const market_min = csMin || (legacyPrices.length ? Math.min(...legacyPrices) : null);
const market_max = csMax || (legacyPrices.length ? Math.max(...legacyPrices) : null);

// ── Build competitor names string for reason ──────────────────────────────
const competitorNames = sourceDetails
  .filter(s => s.similarity_score >= 90)
  .map(s => s.name.replace('Двухкомнатная квартира ', '').replace('Этаж под ключ ', 'Этаж '))
  .join(', ');
const sourceNote = competitorNames
  ? `Рекомендация основана на прямых конкурентах: ${competitorNames}.`
  : 'Рекомендация основана на данных рынка.';
const staleNote = hasStaleData || freshCount === 0
  ? ' Данные seed требуют перепроверки.'
  : '';

// ── Apartments lookup ─────────────────────────────────────────────────────
// (we pull base_price from gap_windows estimated_loss / nights if apartments not loaded)
const aptPrices = {};
for (const g of gaps) {
  if (g.estimated_loss && g.nights && !aptPrices[g.apartment_id]) {
    aptPrices[g.apartment_id] = Math.round(g.estimated_loss / g.nights);
  }
}

const recs = [];

for (const gap of gaps) {
  if (gap.status !== 'open') continue;
  const nights = parseInt(gap.nights);
  if (nights < 1 || nights > 3) continue;

  const base_price = aptPrices[gap.apartment_id] || 6000;
  const hasMarket = market_median !== null;

  // ── Confidence ────────────────────────────────────────────────────────
  let confidence;
  if (!hasMarket) {
    confidence = 0.35;
  } else if (freshCount === 0) {
    confidence = 0.45;   // seed data only
  } else if (freshCount >= 2) {
    confidence = 0.75;
  } else {
    confidence = 0.60;
  }

  // ── Pricing rules ─────────────────────────────────────────────────────
  let recommended_price, recommendation_type, reason;

  if (nights === 1) {
    recommendation_type = 'gap_special_price';
    const candidate1 = base_price * 0.85;
    const candidate2 = hasMarket ? market_median * 0.80 : 0;
    recommended_price = Math.round(Math.max(candidate1, candidate2));
    reason = `Короткое окно 1 ночь: лучше продать спецценой, чем оставить пустым. ${sourceNote}${staleNote}`;
  } else if (nights === 2) {
    recommendation_type = 'gap_special_price';
    const candidate1 = base_price * 0.90;
    const candidate2 = hasMarket ? market_median * 0.90 : 0;
    recommended_price = Math.round(Math.max(candidate1, candidate2));
    reason = `Окно 2 ночи: можно продать коротким заездом со сниженной ценой. ${sourceNote}${staleNote}`;
  } else {
    recommendation_type = 'gap_special_price';
    const candidate1 = base_price;
    const candidate2 = hasMarket ? market_median * 0.95 : 0;
    recommended_price = Math.round(Math.max(candidate1, candidate2));
    reason = `Окно 3 ночи: можно продавать как короткий заезд без сильной скидки. ${sourceNote}${staleNote}`;
  }

  // ── Market raise/lower override ───────────────────────────────────────
  if (hasMarket) {
    if (market_median > base_price * 1.20) {
      recommendation_type = 'raise_price';
      recommended_price = Math.round(market_median * 0.95);
      reason = `Рынок заметно выше базовой цены (+20%). ${sourceNote}${staleNote}`;
    } else if (market_median < base_price * 0.80 && nights <= 2) {
      recommendation_type = 'lower_price';
      recommended_price = Math.round(market_median * 1.05);
      reason = `Рынок ниже текущей цены, есть риск простоя. ${sourceNote}${staleNote}`;
    }
  }

  recs.push({
    apartment_id: gap.apartment_id,
    date_from: gap.gap_start,
    date_to: gap.gap_end,
    nights: nights,
    current_price: base_price,
    market_min: market_min,
    market_median: market_median ? Math.round(market_median) : null,
    market_avg: csWeightedAvg ? Math.round(csWeightedAvg) : null,
    market_max: market_max,
    recommended_price: recommended_price,
    recommendation_type: recommendation_type,
    reason: reason,
    confidence: confidence,
    source: 'c15_weighted_rules',
    status: 'draft'
  });
}

return recs.map(r => ({json: r}));
